mapper.insert:
INSERT INTO bluenote_rank.rank_snapshot (
    snapshot_id, rank_code, period_id, snapshot_type, item_count, source_version, created_at
) VALUES (
    #{snapshotId}, #{rankCode}, #{periodId}, #{snapshotType}, #{itemCount}, #{sourceVersion}, #{createdAt}
)

INSERT INTO bluenote_rank.rank_snapshot_item (
    id, snapshot_id, rank_no, member_type, member_id, score, rank_score, created_at
) VALUES (
    #{id}, #{snapshotId}, #{rankNo}, #{memberType}, #{memberId}, #{score}, #{rankScore}, #{createdAt}
)

mapper.select:
SELECT snapshot_id, rank_code, period_id, snapshot_type, item_count, source_version, created_at
FROM bluenote_rank.rank_snapshot
WHERE rank_code = #{rankCode}
  AND period_id = #{periodId}
  AND snapshot_type = #{snapshotType}
ORDER BY created_at DESC, snapshot_id DESC
LIMIT 1
